// Media seek-latency benchmark. Loads a small VP9 clip from an embedded Blob
// (no network/hosting needed), then repeatedly seeks back and forth between two
// fixed, already-buffered positions a few seconds apart, reporting the time from
// issuing each currentTime= seek to its 'seeked' event. The targets sit far
// apart and mid-GOP, so every seek is a long buffered seek that forces the
// player to re-demux from the prior keyframe and re-decode forward to the
// target. That keyframe->target re-decode is the cost this benchmark tracks.
//
// Each seek is measured in two states so regressions in either are caught:
//   - warm: the video keeps playing, so the decoder stays alive across seeks.
//   - cold: the video is paused so the decoder is released, and each seek
//     recreates it (the timeline-scrubbing case).
// Each measured seek is reported as one replicate.

const { logTest } = require("./utils/profiling");

// 256x144, 30fps, 2s GOP, 10s VP9. The content is irrelevant to the metric;
// only the number of frames from the keyframe to the seek target drives the
// re-decode cost the test is measuring.
const MEDIA_BASE64 =
  "";

// Browser-side measurement script (runs via executeAsyncScript). Kept free of
// template placeholders; the dynamic values are concatenated in below.
const BROWSER_SCRIPT = `
  const notifyDone = arguments[arguments.length - 1];

  function b64ToBlob(b64) {
    const bin = atob(b64);
    const bytes = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) {
      bytes[i] = bin.charCodeAt(i);
    }
    return new Blob([bytes], { type: "video/webm" });
  }

  function seekTo(v, t) {
    return new Promise((resolve) => {
      let done = false;
      const fin = () => {
        if (!done) {
          done = true;
          resolve();
        }
      };
      v.addEventListener("seeked", fin, { once: true });
      v.currentTime = t;
      setTimeout(fin, 4000);
    });
  }

  function measureSeek(v, t) {
    return new Promise((resolve) => {
      const t0 = performance.now();
      v.addEventListener(
        "seeked",
        () => resolve(performance.now() - t0),
        { once: true }
      );
      v.currentTime = t;
      setTimeout(() => resolve(null), 4000);
    });
  }

  function wait(ms) {
    return new Promise((r) => setTimeout(r, ms));
  }

  // Seek SEEKS_PER_LOAD times (after WARMUP discarded warmup seeks), alternating
  // between the two buffered positions earlyTargetSec and lateTargetSec (a few
  // seconds apart, both mid-GOP), and return the per-seek 'seeked' time. The two
  // far-apart targets make every seek a long buffered seek that re-decodes a
  // full keyframe to target run, which is the work being measured. In 'warm' the video keeps
  // playing so the decoder stays alive across seeks; in 'cold' it is paused
  // before each seek so the decoder is released
  // (media.dormant-on-pause-timeout-ms is 0, so the release happens at once) and
  // recreated by the seek.
  async function runPhase(v, mode, earlyTargetSec, lateTargetSec) {
    if (mode === "warm") {
      try {
        await v.play();
      } catch (e) {}
    } else {
      v.pause();
    }
    await seekTo(v, earlyTargetSec);
    const seeked = [];
    // Discard the first WARMUP seeks: the initial seeks after a load run slower
    // while the decode pipeline spins up, so including them widens dispersion
    // without reflecting the steady-state seek cost being measured.
    for (let i = 0; i < WARMUP + SEEKS_PER_LOAD; i++) {
      const target = i % 2 === 0 ? lateTargetSec : earlyTargetSec;
      if (mode === "cold") {
        // Pausing releases the decoder (media.dormant-on-pause-timeout-ms is 0).
        // That release is dispatched off the main thread, so yield one
        // event-loop turn to let it finish before the next seek; that seek then
        // recreates the decoder, which is the cold case being measured.
        v.pause();
        await wait(0);
      }
      const ms = await measureSeek(v, target);
      if (ms !== null && i >= WARMUP) {
        seeked.push(Math.round(ms * 100) / 100);
      }
    }
    return seeked;
  }

  (async () => {
    try {
      const v = document.createElement("video");
      // Muted so play() is allowed under autoplay policies without a user
      // gesture in every browser this test can run in.
      v.muted = true;
      document.body.appendChild(v);
      v.src = URL.createObjectURL(b64ToBlob(B64));
      await new Promise((res, rej) => {
        v.addEventListener("loadeddata", res, { once: true });
        v.addEventListener(
          "error",
          () => rej(new Error("media error " + (v.error && v.error.code))),
          { once: true }
        );
        setTimeout(() => rej(new Error("load timeout")), 20000);
      });

      // The two positions the test alternates seeking between, ~6s apart. Each
      // jump crosses several GOPs, so the player re-demuxes from the prior
      // keyframe and re-decodes forward to the target. Both are mid-GOP (not on
      // a keyframe), so a real keyframe to target run is decoded on every seek.
      const earlyTargetSec = 1.9;
      const lateTargetSec = 7.9;

      const seekedWarm = await runPhase(v, "warm", earlyTargetSec, lateTargetSec);
      v.pause();
      const seekedCold = await runPhase(v, "cold", earlyTargetSec, lateTargetSec);
      notifyDone({ seekedWarm, seekedCold });
    } catch (e) {
      notifyDone({ error: String(e) });
    }
  })();
`;

module.exports = logTest(
  "media seek latency test",
  async function (context, commands) {
    context.log.info("Starting media seek-latency test");

    const post_startup_delay = context.options.browsertime.post_startup_delay;
    // Seeks measured per page load. Replicates come from repeating seeks within
    // a single load rather than from reloads: it is far cheaper and isolates the
    // seek path from page-load variance. The page-load count stays governed by
    // browsertime (page_cycles). WARMUP leading seeks are discarded (runPhase).
    const SEEKS_PER_LOAD = 30;
    const WARMUP = 2;

    await commands.navigate("about:blank");
    await commands.wait.byTime(post_startup_delay);
    await commands.measure.start();

    const script =
      "const SEEKS_PER_LOAD = " +
      SEEKS_PER_LOAD +
      ";\n" +
      "const WARMUP = " +
      WARMUP +
      ";\n" +
      "const B64 = " +
      JSON.stringify(MEDIA_BASE64) +
      ";\n" +
      BROWSER_SCRIPT;

    // The page-side measurement is asynchronous (it awaits seeks and frame
    // callbacks), so run it via executeAsyncScript, which resolves once the
    // script invokes its injected done callback, then read back the timings.
    const result = await context.selenium.driver.executeAsyncScript(script);
    await commands.measure.stop();
    context.log.info("media seek result: " + JSON.stringify(result));

    if (!result || result.error) {
      context.log.error("media seek test failed: " + (result && result.error));
      return false;
    }

    await commands.measure.addObject({
      custom_data: {
        seekedWarm: result.seekedWarm,
        seekedCold: result.seekedCold,
      },
    });
    context.log.info("Media seek-latency test ended");
    return true;
  }
);
